const staticData = $getWorkflowStaticData('node');

const attempts = staticData.attempts ?? 0;
const newAttempts = attempts + 1;

if (newAttempts >= 3) {
    staticData.attempts = 0; // reset for next execution
    return [{ json: { ...$json, attempts: newAttempts, is_failed: 'yes' } }];
}

staticData.attempts = newAttempts;
return [{ json: { ...$json, attempts: newAttempts, is_failed: 'no' } }];

const output = $json.output || '';

const requiredKeywords = [
    ['Commercial', 'Stratégie commerciale'],
    ['Marketing', 'Stratégie marketing'],
    ['Development', 'Développement'],
];

const missingKeywords = requiredKeywords.filter(group =>
    !group.some(kw => output.toLowerCase().includes(kw.toLowerCase()))
);

return [{
    json: {
        ...$json,
        keywords_valid: missingKeywords.length === 0 ? 'true' : 'false',
        missing_keywords: missingKeywords.map(g => g[0]),
    }
}];

const output = $json.output || '';
const minLength = 400;
const length_valid = output.length >= minLength ? 'true' : 'false';

return [{
  json: {
    ...$json,
    length_valid: length_valid,
    actual_length: output.length,
  }
}];

const body = $json.body || $json;
const sectionId = body.section_id;
const input = body.input_json || {};
const context = body.plan_context || {};
const language = body.language || 'english';
const businessPlanId = body.business_plan_id;

const headings = language === 'french' ? `
- Stratégie commerciale
- Stratégie marketing
- Stratégie de développement
` : `
- Commercial Strategy
- Marketing Strategy
- Development Strategy
`;

const prompt = `
You are a senior business strategist writing a professional business plan.

Your task: Write the "Strategy" section of a business plan.
Output language: ${language}

## COMPANY CONTEXT
${context.company_presentation || 'Not provided'}

## MARKET CONTEXT
${context.market_analysis || 'Not provided'}

## ORGANIZATION CONTEXT
${context.org_management || 'Not provided'}

## STRATEGY INPUT DATA
- Commercial Strategy: ${input.commercial_strategy || 'Not provided'}
- Sales Channels: ${input.sales_channels || 'Not provided'}
- Revenue Streams: ${input.revenue_streams || 'Not provided'}
- Pricing Model: ${input.pricing_model || 'Not provided'}
- Marketing Approach: ${input.marketing_approach || 'Not provided'}
- Brand Positioning: ${input.brand_positioning || 'Not provided'}
- Acquisition Channels: ${input.acquisition_channels || 'Not provided'}
- Development Roadmap: ${input.dev_roadmap || 'Not provided'}
- R&D Plans: ${input.rd_plans || 'Not provided'}
- Product Milestones: ${input.product_milestones || 'Not provided'}

## RULES
- Use ONLY the data provided above. Do NOT invent strategies, metrics, or projections.
- For any field marked "Not provided", write: "This strategic element will be defined during the planning phase."
- Connect the strategy directly to market opportunities and organizational capabilities established in the context above.
- Revenue model, pricing, and acquisition channels MUST be internally consistent with each other.
- Write at least 400 words.
- Use formal, strategic business language throughout.
- Structure the section using these headings: ${headings}
- NEVER repeat a sentence, phrase, or paragraph already written earlier in your response. Each paragraph MUST introduce new information.

## OUTPUT FORMAT
Return your response using EXACTLY this structure. Nothing before. Nothing after.

=== SECTION_TEXT ===
[Write the full Strategy section here, using the headings above]

=== MEMORY_SUMMARY ===
Revenue Model: [value or "Not provided"]
Pricing: [value or "Not provided"]
Sales Channels: [value or "Not provided"]
Key Revenue Streams: [value or "Not provided"]
Brand Positioning: [value or "Not provided"]
Acquisition Channels: [value or "Not provided"]
Roadmap Horizon: [earliest to latest milestone date range, or "Not provided"]
`;

return [{
  json: {
    prompt,
    sectionId: sectionId,
    business_plan_id: businessPlanId,
    section_name: 'strategy',
    language,
    input_json: input,
  }
}];

const raw = $('AI Agent').item.json.output || '';

let textMatch = raw.match(/=== SECTION_TEXT ===([\s\S]*?)=== MEMORY_SUMMARY ===/);
let memMatch  = raw.match(/=== MEMORY_SUMMARY ===([\s\S]*?)$/);

if (!textMatch) {
  const parts = raw.split(/===\s*MEMORY_SUMMARY\s*===/i);
  textMatch = parts.length > 1 ? [null, parts[0].replace(/===.*?===/i, '').trim()] : null;
}
if (!memMatch) {
  const parts = raw.split(/===\s*MEMORY_SUMMARY\s*===/i);
  memMatch = parts.length > 1 ? [null, parts[1].trim()] : null;
}

let section_text   = textMatch ? textMatch[1].replace(/^===.*?===\n?/i, '').trim() : raw.trim();
section_text = section_text.replace(/===\s*[^=]*?\s*===/g, '').trim();
const memory_summary = memMatch ? memMatch[1].trim() : '';

const promptText   = $('Build Prompt').item.json.prompt || '';
const tokens_input  = Math.round(promptText.length / 4);
const tokens_output = Math.round(raw.length / 4);
const tokens_total  = tokens_input + tokens_output;

const buildData = $('Build Prompt').item.json;
return [{
  json: {
    ...buildData,
    output: section_text,
    memory_summary,
    tokens_input,
    tokens_output,
    tokens_total,
  }
}];
